#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *next = (int*)calloc(N+1, sizeof(int));
        int *child = (int*)calloc(N+1, sizeof(int));
        int *indeg = (int*)calloc(N+1, sizeof(int));
        for (int i=0;i<N-1;i++) {
            int u,v,type; scanf("%d %d %d", &u, &v, &type);
            if (type==0) { next[u]=v; indeg[v]++; }
            else { child[u]=v; indeg[v]++; }
        }
        int head=1; for (int i=1;i<=N;i++) if (indeg[i]==0) { head=i; break; }
        // iterative DFS using a manual stack
        int *stack = (int*)malloc((N+5)*sizeof(int));
        int top=0; stack[top++] = head;
        int first=1;
        while (top) {
            int u = stack[--top];
            if (!first) printf(" ");
            printf("%d", u);
            first=0;
            if (next[u]) stack[top++] = next[u];
            if (child[u]) stack[top++] = child[u];
        }
        printf("\n");
        free(next); free(child); free(indeg); free(stack);
    }
    return 0;
}

