import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] nxt = new int[N + 1];
            int[] child = new int[N + 1];
            int[] indeg = new int[N + 1];
            for (int i = 0; i < N - 1; i++) {
                int u = fs.nextInt();
                int v = fs.nextInt();
                int type = fs.nextInt();
                if (type == 0) { nxt[u] = v; indeg[v]++; }
                else { child[u] = v; indeg[v]++; }
            }
            int head = 1;
            for (int i = 1; i <= N; i++) if (indeg[i] == 0) { head = i; break; }
            Deque<Integer> stack = new ArrayDeque<>();
            stack.push(head);
            boolean first = true;
            while (!stack.isEmpty()) {
                int u = stack.pop();
                if (!first) out.append(' ');
                out.append(u);
                first = false;
                if (nxt[u] != 0) stack.push(nxt[u]);
                if (child[u] != 0) stack.push(child[u]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }

    // Fast scanner for competitive programming
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

