import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        nxt = [0] * (N + 1)
        child = [0] * (N + 1)
        indeg = [0] * (N + 1)
        for __ in range(N - 1):
            u = int(next(it)); v = int(next(it)); typ = int(next(it))
            if typ == 0:
                nxt[u] = v
                indeg[v] += 1
            else:
                child[u] = v
                indeg[v] += 1
        head = 1
        for i in range(1, N + 1):
            if indeg[i] == 0:
                head = i
                break
        stack = [head]
        res = []
        while stack:
            u = stack.pop()
            res.append(str(u))
            if nxt[u]:
                stack.append(nxt[u])
            if child[u]:
                stack.append(child[u])
        out_lines.append(' '.join(res))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

